import { usePrevious } from ':components/DatePicker/hooks/use-previous';
import { Icon } from ':components/Icon';
import { type Option } from ':components/Select/Select.types';
import { Tooltip } from ':components/Tooltip';
import { Typography } from ':components/Typography';
import { classNames } from ':helpers/classnames';
import { getBEMClasses } from ':helpers/get-bem';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { ChangeEventHandler, FocusEvent, ReactElement, ReactNode } from 'react';
import React, { isValidElement, useCallback, useEffect, useRef, useState } from 'react';

interface UseAutocompleteProps<T> {
	type: 'search' | 'select';
	value: Option<T> | null;
	open?: boolean;
	renderValue: (value: Option<T>) => string;
	enableKeyboardNavigation;
	onOpen?: () => void;
	onClose?: () => void;
	onChange: (value: Option<T>) => void;
	onFocus;
	onBlur;
	onInputChange: (inputValue: string) => void;
	onInputClear: () => void;
	showTooltip?: boolean;
	loading?: boolean;
	hideDropDown?: boolean;
	/**
	 * @deprecated
	 * Будет удалено в следующих релизах, используйте loadingContent
	 */
	loadingText?: string | ReactNode;
	loadingContent?: string | ReactNode;
	options: Array<Option<T>>;
	/**
	 * @deprecated Используйте `noOptionsContents` вместо этого.
	 * Содержимое, отображаемое, когда нет опций для отображения.
	 */
	noOptionsText?: string | ReactNode;
	noOptionsContents?: string | ReactNode;
	makeOption?: (option: Option<T>, inputValue: string) => React.JSX.Element | null;
	className?: string;
	isExtraSmallDevice?: boolean;
}

const highlightingText = (text: string, highlight: string): React.JSX.Element => {
	const escapedHighlight = highlight.replaceAll(/([!$()*+./:=?[\\\]^{|}])/g, '\\$1'); // Экранируем спецсимволы
	const parts = text.split(new RegExp(`(${escapedHighlight})`, 'gi')); // Составляем регулярку с экранированным highlight

	return (
		<span>
			{parts.map((part, i) => (
				<span key={i} style={part.toLowerCase() === highlight.toLowerCase() ? { fontWeight: 'bold' } : {}}>
					{part}
				</span>
			))}
		</span>
	);
};

const [autocompleteClassName, , selectElement] = getBEMClasses('dsb__autocomplete');
const [optionsClassName, , optionsElement] = selectElement('options');
const [itemClassName, itemModifier] = optionsElement('item');

export const useAutocomplete = <T,>(props: UseAutocompleteProps<T>) => {
	const {
		type,
		value,
		open,
		renderValue,
		enableKeyboardNavigation,
		onOpen,
		onClose,
		onChange,
		onFocus,
		onBlur,
		onInputChange,
		onInputClear,
		showTooltip,
		loading,
		hideDropDown,
		loadingText,
		loadingContent,
		options,
		noOptionsContents,
		noOptionsText,
		makeOption,
		className,
		isExtraSmallDevice,
	} = props;

	const innerRef = useRef<HTMLInputElement>(null);
	const optionsRef = useRef<HTMLDivElement>(null);
	const isSearch = type === 'search';

	const [isOpen, setOpen] = useState(hideDropDown ? false : open);
	const [inputValue, setInputValue] = useState(value ? renderValue(value) : '');
	const prevOpen = usePrevious(isOpen);
	const [focusedItem, setFocusedItem] = useState(-1);
	const [maxIndex, setMaxIndex] = useState(0);

	useEffect(() => {
		// Это для того, чтобы при включенном скрыти имы также меняли open на false
		const _open = hideDropDown ? false : open;
		setOpen(_open);
	}, [open, hideDropDown]);

	useEffect(() => {
		if (value) {
			setInputValue(renderValue(value));
		}
	}, [value, renderValue]);

	useEffect(() => {
		if (focusedItem === -1 || !enableKeyboardNavigation) {
			return;
		}
		const focusedElement = optionsRef?.current?.children[focusedItem];
		focusedElement?.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
	}, [focusedItem]);
	// Ручное управление onClose, onOpen не подвязанное к Blur, без UseCallback, потом оптимизировать и вообще отдать управление dropdown
	useEffect(() => {
		if (isOpen && !hideDropDown) {
			onOpen?.();
		}
		if (prevOpen && (!isOpen || hideDropDown)) {
			onClose?.();
		}
	}, [isOpen]);

	useEffect(() => {
		if (focusedItem === -1 || !enableKeyboardNavigation) {
			return;
		}
		const focusedElement = optionsRef?.current?.children[focusedItem];
		focusedElement?.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
	}, [focusedItem]);

	// Вообще надо бы чтобы за это отвечал Дропдаун, зачем этим управлять вручную ?
	const handleOpen = (): void => {
		const _open = !hideDropDown;
		setOpen(_open);
		setTimeout(() => innerRef.current?.focus(), 0);
	};

	const onSelectItem = (item: Option<T>) => () => {
		onChange(item);
		innerRef.current?.focus();
		setOpen(false);
		// обновляем текст в инпуте в случае повторного выбора уже выбранной опции
		if (item?.id === value?.id) {
			setInputValue(renderValue(item));
		}
	};

	const handleClose = (): void => {
		setOpen(false);
	};

	const handleInputFocus = (event: FocusEvent<HTMLInputElement>): void => {
		if (!isOpen) {
			handleOpen();
		}
		onFocus?.(event);
	};

	const handleInputBlur = (event: FocusEvent<HTMLInputElement>): void => {
		// чтобы не отбрасывал ивент, когда выбираешь из списка
		if (!isOpen || hideDropDown) {
			onBlur?.(event);
		}
	};

	const handleInputOnChange: ChangeEventHandler<HTMLInputElement> = event => {
		setInputValue(event.target.value);
		onInputChange(event.target.value);
		handleOpen();
	};

	const handleMaskInputOnChange = (updatedInputValue: string, unmaskedValue: string, event: InputEvent): void => {
		setInputValue(unmaskedValue);
	};

	const handleInputClick = (): void => {
		handleOpen();
	};

	const handleInputOnClear = (): void => {
		setInputValue('');
		onInputClear();
		onInputChange('');
	};

	const defaultMakeOption = (option, inputValue): ReactNode => (
		<Tooltip title={option.value} disableHover={!showTooltip}>
			<Typography variant="body2" ellipsis={true}>
				{highlightingText(option.value, inputValue)}
			</Typography>
		</Tooltip>
	);

	const makeItem = (item: Option<T>, _inputValue: string, index: number): ReactNode => {
		const className = classNames(itemClassName);
		const customComponent = makeOption ? makeOption(item, _inputValue) : defaultMakeOption(item, _inputValue);

		return (
			(customComponent && (
				<div
					key={item.id.toString()}
					data-index={item.id}
					className={classNames(className, focusedItem === index && 'focused')}
					onClick={onSelectItem(item)}
				>
					{isSearch && isExtraSmallDevice && <Icon iconName={Icons.Search} />}
					{customComponent}
				</div>
			)) ||
			null
		);
	};

	const makeOptions = (inputValue: string): ReactElement => {
		if (focusedItem !== -1) {
			// setFocusedItem(-1);
		}
		const makeOptionContent = (): ReactNode => {
			if (loading) {
				const content = loadingText || loadingContent;
				// TODO: поправить после удаления пропса loadingText
				return isValidElement(content) ? (
					content
				) : (
					<span className={itemModifier('empty')}>{content || 'Загрузка'}</span>
				);
			}

			const optionsComponents = options
				.map((item, index) => makeItem(item, inputValue, index))
				.filter(component => component !== null);

			const hasMatching = optionsComponents.length > 0;
			if (hasMatching) {
				const newMaxIndex = optionsComponents.length - 1;
				if (newMaxIndex !== maxIndex && enableKeyboardNavigation) {
					setMaxIndex(newMaxIndex);
				}
				return optionsComponents;
			}

			const noOptionsMessage = noOptionsContents || noOptionsText || 'Нет результатов';

			return isValidElement(noOptionsMessage) ? (
				noOptionsMessage
			) : (
				<span className={classNames(itemClassName, itemModifier('empty'))}>
					{noOptionsMessage || 'Нет результатов'}
				</span>
			);
		};

		return (
			<div className={optionsClassName} ref={optionsRef}>
				{makeOptionContent()}
			</div>
		);
	};

	const optionsComponents = makeOptions(inputValue);

	const handleKeyDown = event => {
		switch (event.key) {
			case 'ArrowUp': {
				if (!isOpen) {
					handleOpen();
				}
				setFocusedItem(Math.max(0, focusedItem - 1));
				break;
			}
			case 'ArrowDown': {
				if (!isOpen) {
					handleOpen();
				}
				setFocusedItem(Math.min(maxIndex, focusedItem + 1));
				break;
			}
			case 'Enter': {
				const selectedIndex = (optionsRef.current?.querySelector('.focused') as HTMLElement)?.dataset.index;
				const selectedItem = options.find(option => option.id.toString() === selectedIndex);
				if (selectedItem) {
					event.preventDefault();
					onSelectItem(selectedItem)();
				}
				event.stopPropagation();
				break;
			}
			case 'Escape': {
				setOpen(false);
				break;
			}
			case 'Tab': {
				setOpen(false);
				break;
			}
			default: {
				setFocusedItem(-1);
			}
		}
	};

	const rootClassName = classNames(autocompleteClassName, className);

	return {
		isOpen,
		innerRef,
		setOpen,
		handleMaskInputOnChange,
		handleClose,
		handleInputBlur,
		handleInputFocus,
		inputValue,
		handleInputOnChange,
		handleInputOnClear,
		handleInputClick,
		rootClassName,
		handleKeyDown,
		isSearch,
		optionsComponents,
	};
};
